import { callMcpSkill, callMcpSkillsParallel } from "@/lib/ai/skills/mcp";

export async function main() {
  const toolId = "b940bedc-3d67-45b0-8709-b3d070e5e454";

  const batch = await callMcpSkillsParallel({
    label: "eth-funding-hyperliquid-vs-binance",
    calls: [
      {
        key: "hyperliquid_market_info",
        toolId,
        toolName: "get_market_info",
        args: { coin: "ETH" }
      },
      {
        key: "cross_venue_funding",
        toolId,
        toolName: "get_funding_analysis",
        args: { coin: "ETH" }
      }
    ]
  });

  const byKey = Object.fromEntries(
    batch.results.map((entry) => [
      entry.key,
      entry.status === "fulfilled" ? entry.value : null
    ])
  );

  const hyperliquid = byKey.hyperliquid_market_info;
  const crossVenue = byKey.cross_venue_funding;

  const currentFunding = crossVenue && typeof crossVenue.currentFunding === "object"
    ? crossVenue.currentFunding
    : null;

  const hyperliquidFunding =
    currentFunding && currentFunding.hyperliquid != null
      ? currentFunding.hyperliquid
      : (hyperliquid && hyperliquid.fundingRate != null ? hyperliquid.fundingRate : null);

  const binanceFunding =
    currentFunding && currentFunding.binance != null
      ? currentFunding.binance
      : null;

  const spread = (hyperliquidFunding != null && binanceFunding != null)
    ? hyperliquidFunding - binanceFunding
    : null;

  const arbitrageSpreadRightNow =
    spread != null && Math.abs(spread) > 0;

  return {
    venueComparison: {
      hyperliquidFunding,
      binanceFunding,
      spread
    },
    arbitrageSpreadRightNow,
    conclusion:
      hyperliquidFunding != null && binanceFunding != null
        ? (spread > 0
            ? "Hyperliquid funding is higher than Binance, so the funding spread is positive."
            : spread < 0
              ? "Binance funding is higher than Hyperliquid, so the funding spread is negative."
              : "The current funding spread is flat."
